INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1, "お！\nあそこに困ってそうな人発見！", 1.4, 0, 2, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", "春咲 ひより", 0, 1, 0, 1, 1001);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1, "大切な人を\n守れるようになりたい…って", 1.4, 0, 2, "みんなみたいに\nわたしも強くならなきゃ", "草野 優衣", 0, 1, 0, 1, 1002);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "少しは磨かれると思いますよ。", 1, "キミに必要な集中力と感性が", 1.4, 0, 2, "フェンシングを始めてみては？", "士条 怜", 0, 1, 0, 1, 1003);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "みそぎはねぇ、\nかくれんぼやりたい！", 1, "今日はなにして遊ぶ？", 1.5, 0, 2, "ねぇ、にいちゃん！", "穂高 みそぎ", 0, 1, 0, 1, 1004);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "私といっしょに…\nいかない？", 1, "ねぇ…", 1.4, 0, 2, "風宮あかりです", "風宮 あかり", 0, 1, 0, 1, 1006);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "食べ物の恨みは怖いのー", 1, "プリンたべたいのー", 1.5, 0, 2, "出雲宮子なのー", "出雲 宮子", 0, 1, 0, 1, 1007);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "いいよ。\n見られることは運命さ…", 1, "キミもボクの美貌に\n吸い寄せられたんだね。", 1.4, 0, 2, "ボクは虹村雪。", "虹村 雪", 0, 1, 0, 1, 1008);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "人呼んで「疾風の冥姫」!!", 1, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1.4, 0, 2, "フッ…聞いて後悔するがいい！", "柊杏奈", 0, 1, 0, 1, 1009);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ほんまおおきにやわ～♪", 1, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1.5, 0, 2, "マホマホ王国のプリンセス、\nまほ姫どす", "姫宮 真歩", 0, 1, 0, 1, 1010);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ここで会ったが\n100年目～！", 1, "生き別れたお兄ちゃんを探して\n三千世界！", 1.4, 0, 2, "衣之咲璃乃です！", "衣之咲 璃乃", 0, 1, 0, 1, 1011);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "…って、お願い！\n誰にも言わないでおいて～！", 1, "ち、超能力って…\n何のことかな～？", 1.4, 0, 2, "私はハツネ、\n結構強いんだよ。\nきらーん☆", "柏崎 初音", 0, 1, 0, 1, 1012);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1, "一応カリスマ読モJKやってまっす！", 1.4, 0, 2, "ちょす！\n美波鈴奈だよ～♪", "美波 鈴奈", 0, 1, 0, 1, 1016);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "でも、沖縄もとってもいいとこさー", 1, "東京は遊園地みたいなところさー", 1.4, 0, 2, "はいたーい。\n喜屋武香織さー。", "喜屋武 香織", 0, 1, 0, 1, 1017);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "イオちゃんって呼んでね。", 1, "先生って呼ばれるのは\nくすぐったいから", 1.4, 0, 2, "支倉伊緒です。", "支倉 伊緒", 0, 1, 0, 1, 1018);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ミミをおいてかないでぇ～", 1, "あ！/\お兄ちゃ～ん\nまってよ～", 1.5, 0, 2, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", "茜 ミミ", 0, 1, 0, 1, 1020);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ふぇぇぇぇぇん……", 1, "あの……\nふぇ……", 1.5, 0, 2, "あ…あの…えっと…\n栗…林…くるみ…です……", "栗林 くるみ", 0, 1, 0, 1, 1021);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "なんてありがとうございます！", 1, "こんな私に貴重な時間を\n割いていただき、", 1.4, 0, 2, "風宮よりです。\nあああああ！", "風宮 より", 0, 1, 0, 1, 1022);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "私こっち行きたいー\nね、早く早くー", 1, "おにいちゃんどこいくの？\nえ？", 1.5, 0, 2, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", "北条 綾音", 0, 1, 0, 1, 1023);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "これて何か違う…\nあああすみません！", 1, "ふ、不束者ですが\nどうぞ末永く…って、", 1.4, 0, 2, "わっ…わっ…私、\n天野すずめといいます！", "天野 すずめ", 0, 1, 0, 1, 1025);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "離しませんわ………\n絶対に…!!", 1, "あなたは…運命の……\n伴侶……", 1.4, 0, 2, "……クスクス…私は\n…倉石恵理子……", "倉石 恵理子", 0, 1, 0, 1, 1027);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "…そうでしょ？？", 1, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1.4, 0, 2, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", "佐々木 咲恋", 0, 1, 0, 1, 1028);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "あはは、\n私もまだまだだなぁ～", 1, "ぇっと…\nキミ、私のこと知らないの?!", 1.4, 0, 2, "桜井望だよ！\nよろしくねっ", "桜井 望", 0, 1, 0, 1, 1029);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ショーグン、\nワタシと一緒に天下統一デース！", 1, "初めまして、\n私はニノン・ジュベール申すデス！", 1.4, 0, 2, "デケデケデンっ！", "ニノン・ジュベール", 0, 1, 0, 1, 1030);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "おかしいですね……", 1, "でもって私の隣にいるのが……\nえ、見えない？", 1.4, 0, 2, "上喜しのぶです。\n手元のドクロが父です。", "上喜 しのぶ", 0, 1, 0, 1, 1031);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そう、\nオラのボケに突っ込める相方が…！", 1, "けんども\nそれには足りないモンが…", 1.5, 0, 2, "目指すはビッグな\nお笑い芸人だっぺ！", "野戸まひる", 0, 1, 0, 1, 1033);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ちょ\nちょっと一杯飲んできます…！", 1, "ちょっと緊張しちゃって…", 1.4, 0, 2, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", "綾瀬 ゆかり", 0, 1, 0, 1, 1034);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "これ以上お話しすることは…\nないです！", 1, "知らない人とは話しちゃいけないので", 1.5, 0, 2, "氷川鏡華…です", "氷川 鏡華", 0, 1, 0, 1, 1036);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1, "……あ、アラーム。", 1.4, 0, 2, "柏崎…栞です。", "柏崎 栞", 0, 1, 0, 1, 1038);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "野に咲く花が、\n唯一の話相手です。", 1, "私、一人も友達がいなくて……", 1.4, 0, 2, "ふ、双葉碧です。", "双葉 碧", 0, 1, 0, 1, 1040);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そう思っています。", 1, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1.4, 0, 2, "三角千歌です。", "三角 千歌", 0, 1, 0, 1, 1042);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "う、疑ってすまなかったな…", 1, "あぁ？\nお前のそいつの仲間か？", 1.4, 0, 2, "安芸真琴だ。", "安芸 真琴", 0, 1, 0, 1, 1043);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1, "生けとし生ける全ての者よ！", 1.4, 0, 2, "わらわこそは夜を総べる者！", "イリヤ・オーンスタイン", 0, 1, 0, 1, 1044);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "ｌク、クウカに何かご用ですか!?", 1, "ぐふふふふ……はっ！", 1.4, 0, 2, "そこで騎士は妖精を乱暴に……", "遠見 空花", 0, 1, 0, 1, 1045);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "う～ん…\n猫ってホントに最高にゃ～♪", 1, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1.4, 0, 2, "宮坂たまきにゃ♪\n猫はいいにゃよ？", "宮坂たまき", 0, 1, 0, 1, 1046);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1, "それでは早速クエストに…", 1.4, 0, 2, "大神美冬よ！", "大神 美冬", 0, 1, 0, 1, 1048);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1, "クエストもバトルも\n掃除も洗濯も", 1.4, 0, 2, "星野静流だよ！", "星野静流", 0, 1, 0, 1, 1049);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1, "見ての通りの\nセクシー美少女で", 1.5, 0, 2, "アタシは玉泉美咲。", "玉泉美咲", 0, 1, 0, 1, 1050);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "？？？？", 1, "？？？？", 1.4, 0, 2, "？？？", "リマ", 0, 1, 0, 1, 1052);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そ、そこまでいうなら\nもらってやる", 1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 2, "モニカ・ヴァイスヴィントだ。", "モニカ・ヴァイスヴィント", 0, 1, 0, 1, 1053);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そ、そこまでいうなら\nもらってやる", 1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 2, "モニカ・ヴァイスヴィントだ。", "ペコリーヌ", 0, 1, 0, 1, 1058);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そ、そこまでいうなら\nもらってやる", 1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 2, "モニカ・ヴァイスヴィントだ。", "コッコロ", 0, 1, 0, 1, 1059);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 0, "そ、そこまでいうなら\nもらってやる", 1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 2, "モニカ・ヴァイスヴィントだ。", "キャル", 0, 1, 0, 1, 1060);
